INSERT INTO detections (
  rule_id, name, description, severity, platform,
  mitre_attack_id, mitre_tactic, mitre_technique,
  nist_controls, data_sources, query, query_language, tags,
  expected_alerts_per_day, expected_fp_rate, expected_mttd_hours,
  is_global, tenant_id, log_sources, device_types
) VALUES
('DET-0401', 'Open Redirect in Splunk Web', 'This search allows you to look for evidence of exploitation for CVE-2016-4859, the Splunk Open Redirect Vulnerability.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1203', 'Execution', 'Exploitation for Client Execution', '{}', '{}', 'index=_internal sourcetype=splunk_web_access return_to="/%09/*"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Any Splunk Logs"}', '{}'),
('DET-0402', 'Suspicious Domain Name', 'Detects algorithmically generated domain names using a machine learning model.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1323', 'Adversary OPSEC', 'Domain Generation Algorithms (DGA)', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS","Web Proxy / NGFW"}', '{"DNS Server","Web Proxy","Next-Gen Firewall"}'),
('DET-0403', 'Flight Risk Printing', 'This search implements two heuristics to look for indications that a user is a flight risk. Many people will print offer letters, drafts of their resume, or related docs on the work environment (for convenience, or because they don''t have a printer at home). Detect when that happens.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1052', 'Exfiltration', 'Exfiltration Over Physical Medium', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit"}', '{}'),
('DET-0404', 'SIEM-E-TA001-XX-New Data Exfil DLP Alerts for User', 'When you first seen an alert from a user who hasn''t generated DLP alerts for data exfiltration before, learn about that.', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Exfiltration', 'Exfiltration', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DLP"}', '{"Data Loss Prevention"}'),
('DET-0405', 'DNS Query Requests Resolved by Unauthorized DNS Servers', 'This search will detect DNS requests resolved by unauthorized DNS servers. Legitimate DNS servers should be identified in the Enterprise Security Assets and Identity Framework.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1043', 'Exfiltration', 'Commonly Used Port', '{}', '{}', '| tstats `summariesonly` count from datamodel=Network_Resolution where DNS.dest_category != dns_server AND DNS.src_category != dns_server by DNS.src DNS.dest | `drop_dm_object_name("DNS")`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"DNS"}', '{"DNS Server"}'),
('DET-0406', 'Substantial Increase In Port Activity', 'Alerts when a statistically significant increase in events on a given port is observed.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1065', 'Command and Control', 'Uncommonly Used Port', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0407', 'Suspicious Data Movement', 'Analyzes different types of data transfers per device and per account, both LAN and WAN, to identify unusual data movements. For example, the model monitors both inter firewall-zones LAN transfers and transfers to different countries and marks transfers that deviate from baseline.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1105', 'Lateral Movement', 'Remote File Copy', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication"}', '{"Firewall","Network Device"}'),
('DET-0408', 'Unusual Time of Badge Access', 'Detects badge access at unusual time.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1360', 'Test Capabilities', 'Test physical access', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Physical Security"}', '{}'),
('DET-0409', 'Short-lived Account Detected', 'Detects when a account or credential is created and then removed a short time later. This may be an indication of malicious activities.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1136', 'Persistence', 'Create Account', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"User Activity Audit","User Activity Audit"}', '{}'),
('DET-0410', 'Completely Inactive Account', 'Discovers accounts that are no longer used. Unused accounts should be disabled and are oftentimes used by attackers to gain unauthorized access.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0411', 'Spike in Exported Records from Salesforce.com', 'For many organizations, Salesforce.com contains the most critical information in their company. This use case tracks the number of records exported per day (and is based on a real set of data collection).Alert Volume: Medium', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail"}', '{"Audit System"}'),
('DET-0412', 'Increase in Source Code (Git) Downloads', 'Find users who have downloaded more files from git than normal.Alert Volume: High', 'HIGH'::detection_severity, 'SPLUNK'::detection_platform, 'T1213', 'Collection', 'Data from Information Repositories', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0413', 'Unusual Activity Time', 'Detects unusual activity time of day, or time of week by a user based on their normal access profile.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Persistence', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication"}', '{"Identity Provider","Active Directory"}'),
('DET-0414', 'Detect mshta.exe running scripts in command-line arguments', 'This search looks for the execution of "mshta.exe" with command-line arguments that launch a script. The search will return the first time and last time these command-line arguments were used for these executions, as well as the target system, the user, process "mshta.exe" and its parent process.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1059', 'Execution', 'Command-Line Interface', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=mshta.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`| search (process=*vbscript* OR process=*javascript*)', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0415', 'Detect Mimikatz Via PowerShell And EventCode 4703', 'This search looks for PowerShell requesting privileges consistent with credential dumping.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1003', 'Credential Access', 'Credential Dumping', '{}', '{}', 'eventtype=wineventlog_security signature_id=4703 Process_Name=*powershell.exe | rex field=Message "Enabled Privileges:\s+(?<privs>\w+)\s+Disabled Privileges:" | where privs="SeDebugPrivilege" | stats count min(_time) as firstTime max(_time) as lastTime by dest, Process_Name, privs, Process_ID, Message | rename privs as "Enabled Privilege" | rename Process_Name as process |  `ctime(firstTime)`| `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Windows Security"}', '{"Windows AD","Windows Endpoint"}'),
('DET-0416', 'RunDLL Loading DLL By Ordinal', 'This search looks for DLLs under %AppData% being loaded by rundll32.exe that are calling the exported function at ordinal 2. Calling exported functions by ordinal is not as common as calling by exported name. There was a bug fixed in IDAPro on 2016-08-08 that would not display functions without names.  Calling functions by ordinal would overcome the lack of name and make it harder for analyst to reverse engineer.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1085', 'Execution', 'Rundll32', '{}', '{}', '| tstats `summariesonly` values(Processes.process) as process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = rundll32.exe Processes.process="*AppData*" Processes.process="*,#2" by Processes.process_name Processes.parent_process_name Processes.dest Processes.user | `drop_dm_object_name(Processes)` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0417', 'Malicious PowerShell Process - Execution Policy Bypass', 'This search looks for PowerShell processes started with parameters used to bypass the local execution policy for scripts. These parameters are often observed in attacks leveraging PowerShell scripts as they override the default PowerShell execution policy.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1086', 'Execution', 'PowerShell', '{}', '{}', '| tstats `summariesonly` count values(Processes.process) as process values(Processes.parent_process) as parent_process min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name=powershell.exe by Processes.user Processes.process_name Processes.parent_process_name Processes.dest  | `drop_dm_object_name(Processes)` | `ctime(firstTime)`| `ctime(lastTime)`| search process=* -ex* OR process=* bypass *', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0418', 'Multiple Authentications', 'Detects outliers in the timeseries of service or machine authentication successes per user.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1078', 'Initial Access', 'Valid Accounts', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Authentication","Windows Security"}', '{"Identity Provider","Active Directory","Windows AD","Windows Endpoint"}'),
('DET-0419', 'Detect attackers scanning for vulnerable JBoss servers', 'This search looks for specific GET or HEAD requests to web servers that are indicative of reconnaissance attempts to identify vulnerable JBoss servers. JexBoss is described as the exploit tool of choice for this malicious activity.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1082', 'Discovery', 'System Information Discovery', '{}', '{}', '| tstats `summariesonly` count min(_time) as firstTime max(_time) as lastTime from datamodel=Web where (Web.http_method="GET" OR Web.http_method="HEAD") AND (Web.url="*/web-console/ServerInfo.jsp*" OR Web.url="*web-console*" OR Web.url="*jmx-console*" OR Web.url = "*invoker*") by Web.http_method, Web.url, Web.src, Web.dest | `drop_dm_object_name("Web")` | `ctime(firstTime)` | `ctime(lastTime)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Web Server"}', '{}'),
('DET-0420', 'First time seen command line argument', 'This search looks for command-line arguments that use a <code>/c</code> parameter to execute a command that has not previously been seen.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1064', 'Execution', 'Scripting', '{}', '{}', '| tstats `summariesonly` min(_time) as firstTime max(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = cmd.exe Processes.process = "* /c *" by Processes.process Processes.process_name Processes.parent_process_name Processes.dest| `drop_dm_object_name(Processes)`| `ctime(firstTime)` | `ctime(lastTime)` | search [| tstats `summariesonly` earliest(_time) as firstTime latest(_time) as lastTime from datamodel=Endpoint.Processes where Processes.process_name = cmd.exe Processes.process = "* /c *" by Processes.process | `drop_dm_object_name(Processes)` | inputlookup append=t previously_seen_cmd_line_arguments | stats min(firstTime) as firstTime, max(lastTime) as lastTime by process | outputlookup previously_seen_cmd_line_arguments | eval newCmdLineArgument=if(firstTime >= relative_time(now(), "-70m@m"), 1, 0) | where newCmdLineArgument=1 | `ctime(firstTime)` | `ctime(lastTime)` | table process]', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0421', 'Registry Keys Used For Privilege Escalation', 'This search looks for modifications to registry keys that can be used to elevate privileges. The registry keys under "Image File Execution Options" are used to intercept calls to an executable and can be used to attach malicious binaries to benign system binaries.', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, 'T1183', 'Privilege Escalation', 'Image File Execution Options Injection', '{}', '{}', '| tstats `summariesonly` count values(Registry.registry_key_name) as registry_key_name values(Registry.registry_path) as registry_path min(_time) as firstTime max(_time) as lastTime FROM datamodel=Endpoint.Registry where (Registry.registry_path="*Microsoft\\Windows NT\\CurrentVersion\\Image File Execution Options*") by Registry.dest , Registry.status, Registry.user | `ctime(lastTime)` | `ctime(firstTime)` | `drop_dm_object_name(Registry)`', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Endpoint Detection and Response"}', '{"EDR","Endpoint"}'),
('DET-0422', 'SIEM-DE-None-XX-EC2 Instance Started In Previously Unseen Region', 'This search looks for CloudTrail events where an instance is started in a particular region in the last one hour and then compares it to a lookup file of previously seen regions where an instance was started', 'MEDIUM'::detection_severity, 'SPLUNK'::detection_platform, NULL, 'Defense Evasion', 'None', '{}', '{}', 'sourcetype=aws:cloudtrail earliest=-1h StartInstances  | stats earliest(_time) as earliest latest(_time) as latest by awsRegion| inputlookup append=t previously_seen_aws_regions.csv | stats min(earliest) as earliest max(latest) as latest by awsRegion | outputlookup previously_seen_aws_regions.csv | eval regionStatus=if(earliest >= relative_time(now(), "-1d@d"), "Instance Started in a New Region","Previously Seen Region") | convert ctime(earliest) ctime(latest) | where regionStatus="Instance Started in a New Region"', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"Audit Trail","AWS"}', '{"Audit System","AWS Cloud"}'),
('DET-0423', 'Vulnerability Scanner Detected (by events)', 'Detects a potential vulnerability scanner by detecting devices that have triggered a large number of unique events. Vulnerability scanners generally trigger a high number unique events when scanning a host since each vulnerability check tends to trigger a unique event.', 'LOW'::detection_severity, 'SPLUNK'::detection_platform, 'T1046', 'Discovery', 'Network Service Scanning', '{}', '{}', '-- No query defined', 'SPL'::query_language, '{}', NULL, NULL, NULL, TRUE, NULL, '{"IDS / IPS"}', '{"IDS/IPS"}'),
('DET-0424', 'Detection ofLogin attempts using SSH', 'Login attempt/Failure: Detection ofLogin attempts using SSH', 'LOW'::detection_severity, 'SIGMA'::detection_platform, NULL, 'Login attempt/Failure', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Event Name Starts with SSH', 'SIGMA'::query_language, '{"NetScreen FW","Login attempt/Failure"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0425', 'Detection of login failure on web interface of the netscreen FW', 'Login attempt/Failure: Detection of login failure on web interface of the netscreen FW', 'MEDIUM'::detection_severity, 'SIGMA'::detection_platform, NULL, 'Login attempt/Failure', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Event Name Contains user login attempt for web management failed', 'SIGMA'::query_language, '{"NetScreen FW","Login attempt/Failure"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0426', 'Detection of policy changes in the Netscreen firewall.', 'Firewall Policy Change tracking: Detection of policy changes in the Netscreen firewall.', 'MEDIUM'::detection_severity, 'SIGMA'::detection_platform, NULL, 'Firewall Policy Change tracking', NULL, '{}', '{}', 'Log Source TypeJuniper Networks Netscreen Firewalls; Event Name endswith policy service; Event Name startswith policy; Event Name contains configuration; Event Name contains Address group; Event Name contains ScheduleOnetime; Event Name startswith Address', 'SIGMA'::query_language, '{"NetScreen FW","Firewall Policy Change tracking"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0427', 'Alerting high CPU utilization on firewall', 'System Health tracking: Alerting high CPU utilization on firewall', 'HIGH'::detection_severity, 'SIGMA'::detection_platform, NULL, 'System Health tracking', NULL, '{}', '{}', 'Log Source TypeJuniper Networks Netscreen Firewalls; Message contains System CPU utilization is high; Netscreen Event ID is 00030', 'SIGMA'::query_language, '{"NetScreen FW","System Health tracking"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0428', 'Alerting  high memory utilization on the firewall. Default is 95% of the total memory', 'System Health tracking: Alerting  high memory utilization on the firewall. Default is 95% of the total memory', 'HIGH'::detection_severity, 'SIGMA'::detection_platform, NULL, 'System Health tracking', NULL, '{}', '{}', 'Log Source TypeJuniper Networks Netscreen Firewalls; message contains System memory is low; Netscreen Event ID is 00020', 'SIGMA'::query_language, '{"NetScreen FW","System Health tracking"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0429', 'High number of deny traffic from the same Internal source IP', 'Internal Malicious User: High number of deny traffic from the same Internal source IP', 'HIGH'::detection_severity, 'SIGMA'::detection_platform, NULL, 'Internal Malicious User', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Event Name = Deny; Source IP belongs to Intenal_LAN; Event Outcome =/Failure; Event Count exceeds 1000 in 10 Minutes', 'SIGMA'::query_language, '{"NetScreen FW","Internal Malicious User"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0430', 'Notify a successful pass from an Internt-IP-source after repetitive blocks in firewall', 'External Malicious User: Notify a successful pass from an Internt-IP-source after repetitive blocks in firewall', 'HIGH'::detection_severity, 'SIGMA'::detection_platform, NULL, 'External Malicious User', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Event Name = Deny; Source IP NOT belongs to Intenal_LAN; Event Outcome =/Failure; Event Count exceeds 1000 in 10 Minutes', 'SIGMA'::query_language, '{"NetScreen FW","External Malicious User"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0431', 'Detection of insecure traffic like FTP,telnet ,VNC on critical servers.', 'Insecure Protocol Usage: Detection of insecure traffic like FTP,telnet ,VNC on critical servers.', 'MEDIUM'::detection_severity, 'SIGMA'::detection_platform, NULL, 'Insecure Protocol Usage', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Destination port In 21,23,5008,4008', 'SIGMA'::query_language, '{"NetScreen FW","Insecure Protocol Usage"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
