('DET-0433', 'Detection of deletion of an admin account', 'Firewall Admin Account Changes: Detection of deletion of an admin account', 'MEDIUM'::detection_severity, 'SIGMA'::detection_platform, NULL, 'Firewall Admin Account Changes', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Message contains Admin account deleted; Netscree Event ID: 00002', 'SIGMA'::query_language, '{"NetScreen FW","Firewall Admin Account Changes"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0434', 'Detection of renaming a Firewall admin account', 'Firewall Admin Account Changes: Detection of renaming a Firewall admin account', 'MEDIUM'::detection_severity, 'SIGMA'::detection_platform, NULL, 'Firewall Admin Account Changes', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Message contains Admin account < > has been modified to < >; Netscree Event ID: 00002', 'SIGMA'::query_language, '{"NetScreen FW","Firewall Admin Account Changes"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0435', 'The link to peer device is down either because of physical cabling issue or NSRP configuration issue', 'High availability: The link to peer device is down either because of physical cabling issue or NSRP configuration issue', 'HIGH'::detection_severity, 'SIGMA'::detection_platform, NULL, 'High availability', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Message contains NSRP; Netscree Event ID: 00015', 'SIGMA'::query_language, '{"NetScreen FW","High availability"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0436', 'An admin has removed all the management access restrictions. Admin can manage the firewall from any of the source Ips', 'System Configuration Changes: An admin has removed all the management access restrictions. Admin can manage the firewall from any of the source Ips', 'HIGH'::detection_severity, 'SIGMA'::detection_platform, NULL, 'System Configuration Changes', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Message contains Management restriction was removed from all IPs and subnets; Netscree Event ID: 00002', 'SIGMA'::query_language, '{"NetScreen FW","System Configuration Changes"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
