('DET-0438', 'An admin has changed the number of port for managing the device via SSH, Telnet or Web', 'System Configuration Changes: An admin has changed the number of port for managing the device via SSH, Telnet or Web', 'MEDIUM'::detection_severity, 'SIGMA'::detection_platform, NULL, 'System Configuration Changes', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Message contains Port has been changed from; Netscree Event ID: 00002', 'SIGMA'::query_language, '{"NetScreen FW","System Configuration Changes"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
('DET-0439', 'An admin has allowed/removed access to the firewall from a particular IP', 'System Configuration Changes: An admin has allowed/removed access to the firewall from a particular IP', 'MEDIUM'::detection_severity, 'SIGMA'::detection_platform, NULL, 'System Configuration Changes', NULL, '{}', '{}', 'Log Source Type Juniper Networks Netscreen Firewalls; Message contains Management restriction for; Netscree Event ID: 00002', 'SIGMA'::query_language, '{"NetScreen FW","System Configuration Changes"}', NULL, NULL, NULL, TRUE, NULL, '{"Network Communication","Firewall Logs","Juniper Netscreen"}', '{"Juniper Netscreen Firewall","Firewall"}'),
